module top_module(
    input wire clk,
    input wire reset,
    input wire in,
    output reg [7:0] count_out
);reg obf_in_prev;

always @(posedge clk, posedge reset) begin
    if (reset) begin
        count_out <= 0;
        obf_in_prev <= 0;
    end
    else begin
        if (in && !obf_in_prev) begin
            count_out <= count_out + 1;
        end
        obf_in_prev <= in;
    end
end

endmodule
